import{_ as a,o as i,c as t,ao as s}from"./chunks/framework.BwTKejc4.js";const m=JSON.parse('{"title":"Simulation plot grammar","description":"","frontmatter":{},"headers":[],"relativePath":"diagnostics-and-validation/simulation-plot-grammar.md","filePath":"diagnostics-and-validation/simulation-plot-grammar.md","lastUpdated":null}'),o={name:"diagnostics-and-validation/simulation-plot-grammar.md"};function r(n,e,l,p,d,c){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="Simulation-plot-grammar" tabindex="-1">Simulation plot grammar <a class="header-anchor" href="#Simulation-plot-grammar" aria-label="Permalink to &quot;Simulation plot grammar {#Simulation-plot-grammar}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Implemented</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/simulation-plot-grammar.html" target="_blank" rel="noreferrer">Simulation plot grammar</a>. DRM.jl keeps the base package <strong>plotting-dependency-free</strong>: the helpers below return the <em>numbers a plot needs</em> — grids, deviances, correlations — so any backend (Makie / Plots / …) renders them in a few lines. This is the data behind drmTMB&#39;s <code>plot_parameter_surface</code> / <code>plot_corpairs</code>.</p></div><p>There are two ingredients: <strong><code>simulate</code></strong> (generate replicate data from a fit) and the <strong>plot-data providers</strong> (turn a fit into plottable grids).</p><h2 id="Simulating-from-a-fit" tabindex="-1">Simulating from a fit <a class="header-anchor" href="#Simulating-from-a-fit" aria-label="Permalink to &quot;Simulating from a fit {#Simulating-from-a-fit}&quot;">​</a></h2><p><code>simulate(fit; rng)</code> draws a parametric replicate of the response from the fitted model — the same machinery the parametric bootstrap (<code>bootstrap_ci</code>) uses:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y_rep </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> simulate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit)            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># one replicate on the response scale</span></span></code></pre></div><p>Re-fitting many replicates and summarising the spread of the estimates is the <strong>recovery study</strong> (ADEMP) pattern used throughout <code>test/</code> — simulate from known coefficients, fit, and check the truth is recovered. That loop is exactly what a simulation plot visualises.</p><h2 id="Plot-data-providers" tabindex="-1">Plot-data providers <a class="header-anchor" href="#Plot-data-providers" aria-label="Permalink to &quot;Plot-data providers {#Plot-data-providers}&quot;">​</a></h2><p>All three return a plain <code>NamedTuple</code> of numbers; you supply the backend.</p><h3 id="profile_curvefit,-k;-npoints-41,-span-3.0,-level-0.95" tabindex="-1"><code>profile_curve(fit, k; npoints = 41, span = 3.0, level = 0.95)</code> <a class="header-anchor" href="#profile_curvefit,-k;-npoints-41,-span-3.0,-level-0.95" aria-label="Permalink to &quot;`profile_curve(fit, k; npoints = 41, span = 3.0, level = 0.95)` {#profile_curvefit,-k;-npoints-41,-span-3.0,-level-0.95}&quot;">​</a></h3><p>The 1-D <strong>profile-likelihood</strong> curve for coefficient index <code>k</code>. At each grid value of <code>θ[k]</code> the nuisance parameters are re-optimised, so it is a genuine likelihood-ratio profile, not a quadratic/Wald approximation. Returns <code>(x, deviance, estimate, cutoff, k, param, coef, level)</code>:</p><ul><li><p><code>x</code> — grid spanning <code>θ̂[k] ± span·se[k]</code>, including the MLE exactly;</p></li><li><p><code>deviance</code> — <code>2(ℓ̂ − ℓ_profile)</code> at each <code>x</code>;</p></li><li><p><code>cutoff</code> — the <code>χ²₁(level)</code> reference line the profile interval inverts.</p></li></ul><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> profile_curve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># plot(pc.x, pc.deviance); hline!([pc.cutoff]); vline!([pc.estimate])</span></span></code></pre></div><h3 id="parameter_surfacefit,-k1,-k2;-npoints-25,-span-3.0" tabindex="-1"><code>parameter_surface(fit, k1, k2; npoints = 25, span = 3.0)</code> <a class="header-anchor" href="#parameter_surfacefit,-k1,-k2;-npoints-25,-span-3.0" aria-label="Permalink to &quot;`parameter_surface(fit, k1, k2; npoints = 25, span = 3.0)` {#parameter_surfacefit,-k1,-k2;-npoints-25,-span-3.0}&quot;">​</a></h3><p>The 2-D profile-deviance <strong>surface</strong> over two coefficients — the data behind <code>plot_parameter_surface</code>. At each node the remaining parameters are profiled out, so <code>z</code> is the true profile deviance, <code>0</code> at the MLE. Returns <code>(x, y, z, k1, k2)</code> with <code>z</code> an <code>npoints × npoints</code> matrix; <code>χ²₂</code> contours give joint confidence regions.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ps </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> parameter_surface</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># contour(ps.x, ps.y, ps.z&#39;)</span></span></code></pre></div><h3 id="corpairs_datafit" tabindex="-1"><code>corpairs_data(fit)</code> <a class="header-anchor" href="#corpairs_datafit" aria-label="Permalink to &quot;`corpairs_data(fit)` {#corpairs_datafit}&quot;">​</a></h3><p>The estimated-coefficient <strong>correlation summary</strong> behind <code>plot_corpairs</code> — the off-diagonal correlations of the coefficient covariance, ready for a pairs / heatmap panel.</p><h2 id="The-Confidence-Eye" tabindex="-1">The Confidence Eye <a class="header-anchor" href="#The-Confidence-Eye" aria-label="Permalink to &quot;The Confidence Eye {#The-Confidence-Eye}&quot;">​</a></h2><p>The figure gallery renders a profile interval as a <strong>Confidence Eye</strong> (a pale lens with a dark outline and a hollow point estimate) drawn directly from <code>profile_curve</code> / <code>confint</code> — a compact, honest depiction of an asymmetric likelihood interval.</p><p>Because every provider returns numbers (not figures), the package stays free of a plotting dependency while remaining fully plottable.</p>',21)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
